// Simple object pool
class VectorPool {
  constructor(size) {
    this.pool = Array.from({ length: size }, () => ({ x: 0, y: 0 }));
    this.index = 0;
  }
  acquire() {
    if (this.index >= this.pool.length) {
      this.pool.push({ x: 0, y: 0 });
    }
    return this.pool[this.index++];
  }
  release() {
    this.index = 0;
  }
}
